package render

import "fmt"

func dhcp6EventHookScript(resourceName, socketPath string) []byte {
	if socketPath == "" {
		socketPath = "/run/routerd/routerd.sock"
	}
	return []byte(fmt.Sprintf(`#!/bin/sh
# Generated by routerd. Do not edit by hand.

socket=${ROUTERD_SOCKET:-%q}
if ! command -v jq >/dev/null 2>&1 || ! command -v curl >/dev/null 2>&1; then
	exit 0
fi

env_json=$(env | jq -Rn 'reduce inputs as $line ({}; ($line | split("="; 2)) as $kv | if ($kv | length) == 2 then . + {($kv[0]): $kv[1]} else . end)')
reason=${reason:-${REASON:-}}
payload=$(jq -n \
	--arg resource %q \
	--arg reason "$reason" \
	--argjson env "$env_json" \
	'{apiVersion:"control.routerd.net/v1alpha1",kind:"DHCP6Event",resource:$resource,reason:$reason,env:$env}')

curl --silent --show-error --fail \
	--unix-socket "$socket" \
	-H 'Content-Type: application/json' \
	--data "$payload" \
	http://routerd/api/control.routerd.net/v1alpha1/dhcp6-event >/dev/null || true
exit 0
`, socketPath, resourceName))
}
